// Function to convert Markdown-formatted text into HTML 
std::string ConvertMarkDownToHTML(const std::string& input) {
    // Step 1: Replace all # symbols with <a> tags 
    const char* p = input.c_str();  
    while (*p) {
        if (*p == '#') {
            std::ostringstream oss;
            oss << " <a href=''>";
            ++p;
        } else {
            oss << *p;
            ++p;
        }
    }

    // Step 2: Replace all _underscores_ with spaces 
    size_t pos = 0, len = input.length(), n;
    for (n=0; n<len; ++n) {
        if (input[n] == '_') {
            oss << ' ';
            pos++;
        } else {
            oss << input[pos];
            pos += 1;
        }
    }

    // Step 3: Return the output string 
    return oss.str();
}

