function checkPrime(arr) {  
    let primes = []; // Array to store found primes

    for (let i=0;i<arr.length-1;i++) {      
        const num = arr[i];        

        // Check all divisors up until sqrt(num)            
        for (let j=2;j<=Math.sqrt(num);j++){         
            if (!(num % j)) {              
                break;                     
            } else {             
                primes.push(num);
                break;
            }
        }
    }

    return primes;
}

